    { id: 'c22', name: 'Japanese Ice Tea', ingredients: ['Vodka', 'Gin', 'Rum Bianco', 'Midori', 'Sweet & Sour', 'Lemonsoda'], image: 'https://images.unsplash.com/photo-1560508179-b2c9a3f8e92b?w=400&h=500&fit=crop', color: '#66CDAA' },
    { id: 'c23', name: 'June Bug', ingredients: ['Midori', 'Malibu', 'Liquore Banana', 'Sweet & Sour', "Succo d'Ananas"], image: 'https://images.unsplash.com/photo-1572590016064-3e5e7e964688?w=400&h=500&fit=crop', color: '#ADFF2F' },
    { id: 'c24', name: 'Long Beach Ice Tea', ingredients: ['Vodka', 'Gin', 'Rum Bianco', 'Triple Sec', 'Sweet & Sour', 'Succo Cranberry'], image: 'https://images.unsplash.com/photo-1546171753-97d7676e4602?w=400&h=500&fit=crop', color: '#DB7093' },
