    { id: 'c29', name: 'Manhattan', ingredients: ['Canadian Whisky', 'Vermouth Rosso', 'Angostura'], image: 'https://images.unsplash.com/photo-1514362545857-3bc16c4c7d1b?w=400&h=500&fit=crop', color: '#800020' },
